    var newGrid = grid.map { Array($0) }
    var subRows = [Array<Int64>]()
    for i in x ... (x + k - 1) {
        let row = newGrid[i]
        let subRow = Array(row[y ... y + k - 1])
        subRows.append(subRow)
    }
    subRows.reverse()
    for i in 0..<k {
        let originalRow = newGrid[x + i]
        let subRow = subRows[i]
        var newRow = originalRow
        for j in 0..<k {
            newRow[y + j] = subRow[j]
        }
        newGrid[x + i] = newRow
    }
    return newGrid
}
