func solve(grid: Array<Array<Int64>>, x: Int64, y: Int64, k: Int64) -> Array<Array<Int64>> {
    var newGrid = grid
    let startRow = Int(x)
    let endRow = startRow + Int(k) - 1
    let submatrixRows = Array(newGrid[startRow...endRow])
    let reversedSubmatrixRows = submatrixRows.reversed()
    for i in 0..<k {
        let originalRow = newGrid[startRow + i]
        let newRow = reversedSubmatrixRows[i]
        for j in 0..<k {
            originalRow[Int(y) + j] = newRow[j]
        }
    }
    return newGrid
}
